+namespace moe::dev::routing {
+namespace routingRenormalize {
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+// Forward declarations of per-kernel launch wrappers (defined in routingRenormalize/*.cu).
+void launchBlockKernel(Data const& data, uint32_t numThreadsHist, void* stream);
+void launchClusterKernel(Data const& data, void* stream);
+void launchHistogramScoresKernel(Data const& data, uint32_t maxNumBlocks, uint32_t numThreadsHist,
+                                 void* stream);
+void launchInitExpertCounts(Data const& data, uint32_t numThreadsHist, void* stream);
+void launchHistogramKernel(Data const& data, int numBlocksHistogram, uint32_t numThreadsHist,
+                           void* stream);
+void launchOffsetsKernel(Data const& data, int numBlocksOffsets, uint32_t numThreadsHist,
+                         void* stream);
+
+////////////////////////////////////////////////////////////////////////////////////////////////////
+void run(Data const& data, void* stream) {
+  FLASHINFER_CHECK(
+      data.mPtrTopKPacked != nullptr || data.mPtrScores != nullptr || data.mPtrTopKIds != nullptr,
+      "Routing kernel requires at least one input parameter");
+  if (data.mPtrTopKIds != nullptr) {
+    FLASHINFER_CHECK(data.mPtrTopKWeights != nullptr,
+                     "When mPtrTopKIds is provided, mPtrTopKWeights must also be provided for "
+                     "Renormalize routing.");
+  }
+  FLASHINFER_CHECK(
+      data.mPtrPermutedIdxSize != nullptr && data.mPtrCtaIdxXyToBatchIdx != nullptr &&
+          data.mPtrCtaIdxXyToMnLimit != nullptr && data.mPtrNumNonExitingCtas != nullptr,
+      "Renormalize routing kernel expects permuted idx and grouped Gemm launch config buffers");
+  FLASHINFER_CHECK(data.mTopK <= MaxSupportedTopExperts,
+                   "Routing kernel expects topK experts <= %d, got %d", MaxSupportedTopExperts,
+                   data.mTopK);
+  FLASHINFER_CHECK(data.mNumExperts <= MaxSupportedExperts,
+                   "Routing kernel expects #experts %d to be no more than %d", data.mNumExperts,
+                   MaxSupportedExperts);
+  FLASHINFER_CHECK(data.mNumExperts % 4 == 0,
+                   "Routing kernel expects #experts %d to be a multiple of 4.", data.mNumExperts);
+
+  bool const useSingleBlock =
+      data.mNumTokens <= BlockKernelMaxNumTokens && data.mPtrTopKPacked == nullptr;
+
+  bool const useSingleCluster =
+      data.mNumTokens <= ((data.mPtrScores != nullptr || data.mPtrTopKIds != nullptr)
+                              ? MaxNumTokensSingleClusterScores
+                              : MaxNumTokensSingleCluster);
+
+  if (!useSingleCluster && !useSingleBlock) {
+    FLASHINFER_CHECK(
+        (data.mPtrTopKPacked != nullptr || data.mPtrTopKIds != nullptr),
+        "When #tokens is large, `mPtrTopKPacked` or `mPtrTopKIds` is a required input.");
+    FLASHINFER_CHECK(data.mPtrExpertCounts != nullptr,
+                     "When #tokens is large, `mPtrExpertCounts` is a required input.");
+  }
+  uint32_t const numThreadsHist = min(1024, getMaxNumExperts(data.mNumExperts));
+  if (useSingleBlock) {
+    launchBlockKernel(data, numThreadsHist, stream);
+  } else if (useSingleCluster) {
+    launchClusterKernel(data, stream);
+  } else {
+    uint32_t const expandedIdxSize = data.mNumTokens * data.mTopK;
+    uint32_t const histogramEltsPerBlock = 8 * numThreadsHist;
+    uint32_t const offsetEltsPerBlock = NumEltsPerOffsetTilePerThread * numThreadsHist;
+
+    uint32_t const maxNumBlocks = 1024;
+
+    int const numBlocksHistogram = std::min(
+        (expandedIdxSize + histogramEltsPerBlock - 1) / histogramEltsPerBlock, maxNumBlocks);
+    int const numBlocksOffsets =
+        std::min((expandedIdxSize + offsetEltsPerBlock - 1) / offsetEltsPerBlock, maxNumBlocks);
+
+    if (data.mPtrScores != nullptr && data.mPtrTopKIds == nullptr) {
+      launchHistogramScoresKernel(data, maxNumBlocks, numThreadsHist, stream);
+    } else {
+      launchInitExpertCounts(data, numThreadsHist, stream);
+    }
+    launchHistogramKernel(data, numBlocksHistogram, numThreadsHist, stream);
+    launchOffsetsKernel(data, numBlocksOffsets, numThreadsHist, stream);
+  }
+}
